var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"휴우, 추워. 여긴 뭐가 이렇게 쏟아지는 걸까요? 잿가루?","JPN":"うう、寒い。これ、何が降ってるんですか？　灰？","ENG":"Whew, it's cold. What's all that coming down from the sky? Ashes?","TWN":"呼，好冷。這裡下的是什麼東西？是灰嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"눈이란 것이다. 사계가 존재하던 때엔 동절기가 오면 비를 대신해 내리곤 했지.","JPN":"雪というものだ。四季が存在していたころ、冬になると雨の代わりに降っていた。","ENG":"It is called snow. When there were four seasons, snow would replace rain in the winter.","TWN":"這就是雪。在四季分明的過去，冬天會下雪 。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"신기하네요. 밟으면 뽀스락거리고 제 발자국도 남아요.","JPN":"不思議ですね。踏むとサクサクしていて、足跡も残るんですね。","ENG":"It's amusing. It makes a squishy sound, and I can see my footprints too.","TWN":"好神奇啊。踩上去會發出沙沙響，還會留下腳印。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"무얼 하는 거지?","JPN":"何をしている？","ENG":"What are you doing?","TWN":"你在做什麼？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"잠시만요.","JPN":"ちょっと待ってくださいね。","ENG":"Just a moment.","TWN":"等我一下。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"짜안-","JPN":"ジャーン！","ENG":"Ta-da!","TWN":"鏘鏘——"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"눈인형을 만들어봤어요.","JPN":"雪だるまを作ってみました。","ENG":"I made a snow doll.","TWN":"我做了個雪人。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"인형…?","JPN":"雪だるま……？","ENG":"Snow doll...?","TWN":"雪人……？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"덩어리를 뭉쳐서 구멍으로 눈코입을 만든 것뿐이지만요.","JPN":"丸い塊を作って、穴で目と鼻と口を作っただけですけど。","ENG":"I just made it into a ball and poked holes in it to make a face.","TWN":"我把雪堆成球狀後，挖了洞做成了眼耳鼻。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"단순하지만, 제법 앙증맞게 생겼군. 손재주가 좋구나.","JPN":"単純だが、なかなか可愛らしいな。手先が器用だ。","ENG":"Simple, but endearing. You are good with your hands.","TWN":"雖然很簡單，但確實很可愛。好手藝。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"헤헤, 일을 나간 언니가 돌아올 때까지 저는 흙으로 인형을 만들면서 놀곤 했거든요.","JPN":"へへ、仕事に行ったお姉さんが帰って来るまで、土で人形を作りながら遊んでたんです。","ENG":"Heh heh, I used to make dolls out of mud while my sister was out for work.","TWN":"嘿嘿，在以前姊姊出去工作後，我就經常一個人用泥土捏成人偶玩，等待姊姊回來。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"진짜 인형은 아니긴 하지만… 나중에 돈벌면 진짜 재료를 사서 연습할 거예요!","JPN":"本物の人形じゃないですけど……大きくなってお金を稼いだら、材料を買って練習します！","ENG":"It's not a real doll, but... when I get a job, I'm going to buy the proper materials and start practicing!","TWN":"雖然不是真正的娃娃……但以後我賺夠了錢，我會買真材實料來練習！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너의 누이는… 약초를 찾으러 떠났다가 돌아오지 않았다고 했지.","JPN":"そなたの姉は……薬草探しに家を出たきり、帰ってこなかったと言っていたな。","ENG":"You had mentioned... that your sister never returned after departing on a quest for herbs.","TWN":"你姊姊……聽你說在出去採集草藥後，就再也沒回來。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"흰 서리꽃. 그게 있어야 제 병이 낫는다고 했어요.","JPN":"白い霜の花。それがないと私の病気が治らないって。","ENG":"The white frost flowers. She said she needed those to cure my illness.","TWN":"白色的霜花，她說只有那種花才能治好我的病。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"그때 언니를 혼자 보내지 말 걸… 언니를 찾는 지금도 계속 후회하고 있어요.","JPN":"あの時お姉さんを一人で行かせるべきじゃなかった……今でもずっと後悔しています。","ENG":"I shouldn't have let her go alone... I regret making that choice, the more I search for her.","TWN":"我真不應該讓她一個人走……直到現在也在後悔。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너는 태양문 바깥의 설원에서 며칠씩이나 홀로 살아남았다.","JPN":"そなたは太陽の門の外にある雪原で、何日も一人で生き残った。","ENG":"You were alone on the snow-covered fields beyond the Solar Gates. And yet, you survived.","TWN":"你曾在太陽門外的雪地裡獨自生存了數日。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"나와 만났을 때도 마물들과 대등하게 맞서 싸우고 있었지.","JPN":"我と出会った時にも、魔物と対等に立ち向かい、戦っていた。","ENG":"You were neck and neck in your fight against those monsters when I encountered you.","TWN":"我們相遇的時候，你也在和怪物們勢均力敵地戰鬥。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내가 판단하기에 너는 약이 필요할 정도의 병자로 보이진 않는구나.","JPN":"我が判断するに、そなたは薬が必要であるほど病弱には見えぬ。","ENG":"In my eyes, you do not seem to be a patient in need of medicine.","TWN":"在我看來，你並不是一個需要草藥來救治的病人。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"어… 그건 칭찬인가요?","JPN":"えっと……それは褒めてるんですか？","ENG":"Uh... Is that a compliment?","TWN":"呃……這算是誇我嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그래, 가족을 찾기 위해 두려움을 무릅쓰고 겨울의 한복판까지 왔다는 건 대견하구나.","JPN":"ああ、家族を探すために恐怖を克服し、冬の寒さの中生き残ったのは称賛に値する。","ENG":"Yes. It is commendable that, despite your fears, you made it to the wilds of winter in search of your family.","TWN":"是的，你為了尋找家人而忍住恐懼走到這一步，很令人欽佩。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"와아! 고맙습니다!","JPN":"わあ！　ありがとうございます！","ENG":"Whoa! Thank you!","TWN":"哇，謝謝你！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"언니도 칭찬은 잘 안 해주거든요!","JPN":"お姉さんは私のこと、あんまり褒めてくれなかったんです！","ENG":"Not even my sister compliments me often!","TWN":"連我姊姊也不太會誇獎我呢！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"하지만 소녀여. 이곳 바깥은 네가 계속 머물기엔 너무도 위험하다.","JPN":"だが、少女よ。外はそなたが留まるにはあまりにも危険だ。","ENG":"However, these outer areas are far too perilous for you to stay in, girl.","TWN":"但是，這外面的世界對你這樣的女孩來說太危險了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내가 거느린 악단이 연주를 통해 태양문의 빛을 유지하고 있으니, 그 빛을 쫓아 집으로 돌아가거라.","JPN":"我が率いる楽団が、演奏を通じて太陽の門の光を維持している。その光を追って、自宅へ帰れ。","ENG":"The Orchestra under my command is performing to keep the Solar Gates lit. You are to follow the light and return home.","TWN":"我的樂團會透過演奏讓太陽門的光芒永存，你就跟隨那道光芒回家吧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"읏차- 여긴 턱이 높네요.","JPN":"よいしょっと～ここは段差が大きいですね。","ENG":"Oof. That was a tough climb.","TWN":"哎呀——這裡的檻比較高。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"제 손잡으세요. 갑옷 때문에 혼자 올라오기 불편하실 거예요.","JPN":"ほら、掴まってください。鎧のせいで一人で登るのは大変でしょう？","ENG":"Take my hand. Your armor might make it difficult for you to come up here on your own.","TWN":"抓住我的手。你穿著盔甲，一個人很難爬上來。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"돌아가지 않는 건가?","JPN":"帰らぬのか？","ENG":"Are you not returning?","TWN":"不回去了？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"에클레시아 님은 마왕이란 나쁜 괴물을 처단하러 왔다고 하셨죠?","JPN":"エクレシア様は、魔王っていう悪い化け物を処断しに来たって言いましたよね？","ENG":"Miss Ecclesia, you said that you were here to exterminate the evil monster called the Demon Lord, right?","TWN":"艾可露西亞是來擊敗一個叫魔王的壞蛋對嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"저희 같은 엘리시온의 사람들이 안전하게 지낼 수 있도록 말이예요.","JPN":"私たちみたいなエリシオンの人たちが安全に暮らせるように。","ENG":"So the people of Elysion could be safe.","TWN":"為了讓我們這些屬艾利森的人能夠安全生活。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Correct.","TWN":"是的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"그럼 제가 도와드릴게요!","JPN":"なら、私が力になります！","ENG":"Then I'll help!","TWN":"那就讓我來幫你吧！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"언니는 제가 병자라서 아무한테도 도움이 안 될 거라고 했지만… 에클레시아 님 말씀처럼 저 꽤 강하거든요.","JPN":"お姉さんは、私が病人だから役には立たないって言ってたけど……。エクレシア様の言うとおり実は私、結構強いんです。","ENG":"My sister said I won't be of any help because I'm sick, but... like you said, I'm pretty strong.","TWN":"我姊姊說我體弱多病，只會拖累別人……但就像艾可露西亞你說的，其實我很堅強。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네가 날 돕는다고?","JPN":"そなたが我を手伝うと？","ENG":"You wish to help me?","TWN":"你要幫我？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"모두를 위해 애쓰시는 건데, 혼자서 싸우는 건 외롭잖아요?","JPN":"みんなのために頑張ってるのに、一人で戦うのは寂しいでしょう？","ENG":"You're out here trying to help everyone. But it must be lonely to fight alone!","TWN":"你為了大家獨自一人戰鬥，豈不是很孤單嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"어쩌면 언니가 그 나쁜 마왕에게 붙잡혀 있을 지도 모르고요.","JPN":"もしかしたら、お姉さんがあの悪い魔王に捕まっているかもしれませんし。","ENG":"And my sister might be captured by that evil Demon Lord.","TWN":"而且姊姊或許也被那個壞魔王綁架了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"앗? 제가 말실수한 건 아니죠?","JPN":"あれっ？　私なにか変なこと言いました？","ENG":"Oh! Did I say the wrong thing?","TWN":"啊？我是不是說錯了什麼？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"아니…","JPN":"いや……","ENG":"No...","TWN":"不……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"넌 아무런 실수도 하지 않았다.","JPN":"そなたは何の失言もしておらん。","ENG":"You have done nothing wrong.","TWN":"你沒有犯任何錯誤。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"하지만 조심하거라. 험난한 여정이 될 테니.","JPN":"だが、気をつけるが良い。険しい道のりになるだろう。","ENG":"However, you must be cautious. As this will be a treacherous journey.","TWN":"但要小心，這將是一段艱難的旅程。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"앗, 알겠습니다!","JPN":"はいっ！","ENG":"Ah, okay!","TWN":"啊，我明白了！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"그럼, 제가 마른 장작을 찾아볼 테니 에클레시아 님은 불 피울 만한 곳을 알아봐 주세요!","JPN":"では私は薪を探してくるので、エクレシア様は火を焚けるような場所を探してください！","ENG":"Then, I'll go look for some dry wood, and you can look for a place where we can start a campfire!","TWN":"那麼我去找些乾柴，請你找個地方生火吧！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"아까부터 손이 너무 시렸거든요.","JPN":"さっきから手が冷たくて。","ENG":"My hands are freezing.","TWN":"我的手快要凍僵了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"존재해선 안 될 악취가… 느껴지는구나.","JPN":"存在してはいけない悪臭が……感じられるな。","ENG":"I sense the stench... that should not exist.","TWN":"我聞到了一股……不應該有的惡臭。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 땅에도… 종말이 도래하려는 것인가.","JPN":"この地にも……終末が到来するのか。","ENG":"Will this realm... reach the apocalypse as well?","TWN":"末日……就要臨到這片土地了嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그때처럼…","JPN":"あの時のように……","ENG":"Like that time…","TWN":"就像那時……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"커억… 크허헉…","JPN":"がはっ……くうっ……","ENG":"Kgh... Khhhk...","TWN":"咳……咳咳……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GATE_NPC_CHARADE_NULL","text":{"KOREA":"섹터E7. 방금 침입센서가 작동했던데, 무슨 일이지?","JPN":"セクターE7。今侵入センサーが作動したが、どうした？","ENG":"Sector E7. We noticed the intruder alert go off just now. What's going on?","TWN":"E7防區，入侵感測器剛剛響了。怎麼回事？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GATE_NPC_CHARADE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"…별일 아니었습니다.","JPN":"……大したことではありませんでした。","ENG":"...It was nothing.","TWN":"……沒什麼。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GATE_NPC_CHARADE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"산짐승이 내부로 들어오려 해서… <color=#ff3636>잡았습니다.</color>","JPN":"獣が内部に入ろうとしていたので……<color=#ff3636>倒しました</color>。","ENG":"A wild animal was trying to come in... so I <color=#ff3636>handled it.</color>","TWN":"有一隻野獸試圖鑽進去……<color=#ff3636>已經被我抓到了。</color>"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GATE_NPC_CHARADE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GATE_NPC_CHARADE_NULL","text":{"KOREA":"그런가.","JPN":"そうか。","ENG":"I see.","TWN":"是嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GATE_NPC_CHARADE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GATE_NPC_CHARADE_NULL","text":{"KOREA":"침식지대에서 왔을 확률이 높으니 최대한 빨리 소각하도록.","JPN":"侵食地帯から来た確率が高いから、なるべく早く焼却しろ。","ENG":"It's likely from a Corrupted area. Dispose of it as soon as possible.","TWN":"牠有可能來自侵蝕地區，儘快處理掉。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GATE_NPC_CHARADE_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};